import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { updateProfile } from "../services/authService"; // assuming similar service
import './setting.css';

const Setting = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    subject: ''
  });
  
  const [loading, setLoading] = useState(false); // from Signup
  const navigate = useNavigate(); // from Signup

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // Signup.jsx style handleSubmit with loading state
  const handleSubmit = async (e) => {
    e.preventDefault();
    
    setLoading(true); // from Signup
    
    // Validate required fields (from Signup)
    if (!formData.name || !formData.email) {
      alert("Please fill all required fields!");
      setLoading(false);
      return;
    }
    
    try {
      console.log("Updated Data:", formData);
      
      // API call like Signup pattern
      // await updateProfile(formData);
      
      alert("Profile updated successfully!"); // from Signup
      
      // Optional: navigate after update
      // navigate("/profile");
      
    } catch (err) { // from Signup error handling
      console.error("Update Error:", err);
      alert("Update failed 😢 " + (err.message || "Please try again"));
    } finally { // from Signup
      setLoading(false);
    }
  };

  return (
    <div className="settings-container">
      <h1 className="title">⚙️ <span className='stng'>Settings</span></h1>

      <form className="settings-form" onSubmit={handleSubmit}>

        <label>Name *</label>
        <input
          type="text"
          name="name"
          placeholder="Enter your name"
          value={formData.name}
          onChange={handleChange}
        />

        <label>Email *</label>
        <input
          type="email"
          name="email"
          placeholder="Enter your email"
          value={formData.email}
          onChange={handleChange}
        />

        <label>Password</label>
        <input
          type="password"
          name="password"
          placeholder="New password"
          value={formData.password}
          onChange={handleChange}
        />

        <label>Subject</label>
        <input
          type="text"
          name="subject"
          placeholder="Enter subject (e.g. Math)"
          value={formData.subject}
          onChange={handleChange}
        />

        <button type="submit" className="save-btn" disabled={loading}> {/* disabled from Signup */}
          {loading ? "Saving..." : "Save Changes"} {/* loading text from Signup */}
        </button>

      </form>
    </div>
  );
};

export default Setting;
